using System;
using System.Runtime.InteropServices;
using System.Security;
using System.Security.Cryptography;
using System.Text;

// Secure credential storage using SecureString
public class SecureCredentialHandler
{
    // Store password as SecureString (encrypted in memory)
    public static SecureString GetPasswordSecurely()
    {
        SecureString securePassword = new SecureString();

        Console.Write("Enter password: ");
        while (true)
        {
            ConsoleKeyInfo key = Console.ReadKey(true);
            if (key.Key == ConsoleKey.Enter) break;

            securePassword.AppendChar(key.KeyChar);
            Console.Write("*");
        }

        securePassword.MakeReadOnly();
        return securePassword;
    }

    // Convert SecureString to byte array for use (then zero immediately)
    public static byte[] SecureStringToByteArray(SecureString secureString)
    {
        IntPtr ptr = IntPtr.Zero;
        try
        {
            ptr = Marshal.SecureStringToGlobalAllocUnicode(secureString);
            byte[] bytes = Encoding.Unicode.GetBytes(
                Marshal.PtrToStringUni(ptr)
            );
            return bytes;
        }
        finally
        {
            // CRITICAL: Zero memory immediately
            if (ptr != IntPtr.Zero)
            {
                Marshal.ZeroFreeGlobalAllocUnicode(ptr);
            }
        }
    }

    // Encrypt sensitive data using DPAPI
    public static byte[] ProtectData(string plaintext)
    {
        byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);

        try
        {
            // Encrypt data using machine key (only this machine can decrypt)
            byte[] encryptedBytes = ProtectedData.Protect(
                plaintextBytes,
                entropy: null,
                scope: DataProtectionScope.LocalMachine
            );

            return encryptedBytes;
        }
        finally
        {
            // Zero plaintext bytes immediately
            Array.Clear(plaintextBytes, 0, plaintextBytes.Length);
        }
    }

    // Decrypt DPAPI-protected data
    public static string UnprotectData(byte[] encryptedData)
    {
        byte[] decryptedBytes = null;
        try
        {
            decryptedBytes = ProtectedData.Unprotect(
                encryptedData,
                entropy: null,
                scope: DataProtectionScope.LocalMachine
            );

            return Encoding.UTF8.GetString(decryptedBytes);
        }
        finally
        {
            // Zero decrypted bytes immediately after use
            if (decryptedBytes != null)
            {
                Array.Clear(decryptedBytes, 0, decryptedBytes.Length);
            }
        }
    }

    // Secure database connection string handling
    public static void ConnectToDatabaseSecurely()
    {
        SecureString securePassword = GetPasswordSecurely();

        // Build connection string with SecureString
        var connectionStringBuilder = new System.Data.SqlClient.SqlConnectionStringBuilder
        {
            DataSource = "myserver.database.windows.net",
            InitialCatalog = "mydb",
            UserID = "myuser",
            // DO NOT SET Password property - use SecureString instead
        };

        using (var connection = new System.Data.SqlClient.SqlConnection())
        {
            // Set connection string without plaintext password
            connection.ConnectionString = connectionStringBuilder.ConnectionString;

            // Use Windows Authentication or Azure AD Managed Identity instead
            // This avoids storing passwords in memory entirely
            connectionStringBuilder.IntegratedSecurity = true;

            connection.Open();
            // Use connection...
        }

        // SecureString will be zeroed when disposed
        securePassword.Dispose();
    }

    // Zero sensitive byte arrays after use
    public static void ZeroMemory(byte[] sensitiveData)
    {
        if (sensitiveData != null)
        {
            Array.Clear(sensitiveData, 0, sensitiveData.Length);
        }
    }
}

// Example usage
public class Program
{
    public static void Main()
    {
        // Store API key encrypted in memory
        string apiKey = "sk-1234567890abcdef";
        byte[] encryptedKey = SecureCredentialHandler.ProtectData(apiKey);

        // Zero original plaintext immediately
        apiKey = null;
        GC.Collect();

        // Use encrypted key when needed
        string decryptedKey = SecureCredentialHandler.UnprotectData(encryptedKey);
        // ... use decryptedKey ...

        // Zero decrypted key immediately after use
        decryptedKey = null;
        GC.Collect();
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <keyutils.h>
#include <errno.h>

// Store credentials in kernel keyring (not accessible via process memory dump)
int store_credential_in_keyring(const char* key_name, const char* credential)
{
    key_serial_t key;

    // Create key in user session keyring
    key = add_key(
        "user",                    // Key type
        key_name,                  // Key description/name
        credential,                // Payload (credential)
        strlen(credential),        // Payload length
        KEY_SPEC_USER_KEYRING     // Keyring ID (user session)
    );

    if (key < 0) {
        perror("Failed to add key to keyring");
        return -1;
    }

    // Set key timeout (auto-delete after 1 hour)
    if (keyctl(KEYCTL_SET_TIMEOUT, key, 3600) < 0) {
        perror("Failed to set key timeout");
        return -1;
    }

    // Revoke key access from other processes
    if (keyctl(KEYCTL_SETPERM, key, KEY_POS_VIEW | KEY_POS_READ) < 0) {
        perror("Failed to set key permissions");
        return -1;
    }

    printf("Credential stored in kernel keyring (key_id: %d)\n", key);
    return key;
}

// Retrieve credential from kernel keyring
char* get_credential_from_keyring(const char* key_name)
{
    key_serial_t key;
    char buffer[1024];
    int ret;

    // Search for key in user keyring
    key = keyctl_search(KEY_SPEC_USER_KEYRING, "user", key_name, 0);
    if (key < 0) {
        perror("Key not found in keyring");
        return NULL;
    }

    // Read key payload
    ret = keyctl_read(key, buffer, sizeof(buffer));
    if (ret < 0) {
        perror("Failed to read key from keyring");
        return NULL;
    }

    buffer[ret] = '\0';
    return strdup(buffer);
}

// Revoke credential from keyring
int revoke_credential(const char* key_name)
{
    key_serial_t key;

    key = keyctl_search(KEY_SPEC_USER_KEYRING, "user", key_name, 0);
    if (key < 0) {
        return -1;
    }

    // Revoke key (make it inaccessible)
    if (keyctl(KEYCTL_REVOKE, key) < 0) {
        perror("Failed to revoke key");
        return -1;
    }

    printf("Credential revoked from keyring\n");
    return 0;
}

// Example: Store database password in kernel keyring
int main()
{
    const char* db_password = "MyS3cureP@ssw0rd";
    char* retrieved_password;

    // Store password in kernel keyring (not in process memory)
    int key_id = store_credential_in_keyring("db_password", db_password);
    if (key_id < 0) {
        return 1;
    }

    // Zero plaintext password from stack
    memset((void*)db_password, 0, strlen(db_password));

    // Later, retrieve password from keyring when needed
    retrieved_password = get_credential_from_keyring("db_password");
    if (retrieved_password) {
        printf("Retrieved password: %s\n", retrieved_password);

        // Use password for database connection...

        // Zero and free retrieved password
        memset(retrieved_password, 0, strlen(retrieved_password));
        free(retrieved_password);
    }

    // Revoke key when no longer needed
    revoke_credential("db_password");

    return 0;
}

