using Azure.Identity;
using Azure.Security.KeyVault.Secrets;
using Azure.Core;
using System;
using System.Threading.Tasks;

public class SecretManager
{
    private readonly SecretClient _secretClient;
    private readonly TokenCredential _credential;

    public SecretManager(string keyVaultUrl)
    {
        // Use Managed Identity (no credentials in code/memory)
        _credential = new DefaultAzureCredential();
        _secretClient = new SecretClient(new Uri(keyVaultUrl), _credential);
    }

    // Retrieve secret from Key Vault (never stored in memory longer than needed)
    public async Task<string> GetSecretAsync(string secretName)
    {
        try
        {
            KeyVaultSecret secret = await _secretClient.GetSecretAsync(secretName);
            return secret.Value;
        }
        catch (Exception ex)
        {
            throw new Exception($"Failed to retrieve secret '{secretName}': {ex.Message}");
        }
    }

    // Store new secret in Key Vault
    public async Task<KeyVaultSecret> SetSecretAsync(string secretName, string secretValue)
    {
        return await _secretClient.SetSecretAsync(secretName, secretValue);
    }

    // Database connection using Key Vault (no plaintext connection strings)
    public async Task<string> GetDatabaseConnectionStringAsync()
    {
        // Retrieve individual components (not full connection string)
        string server = await GetSecretAsync("db-server");
        string database = await GetSecretAsync("db-name");
        string username = await GetSecretAsync("db-username");
        string password = await GetSecretAsync("db-password");

        // Build connection string on-the-fly
        string connectionString = $"Server={server};Database={database};" +
                                 $"User Id={username};Password={password};" +
                                 "Encrypt=true;TrustServerCertificate=false;";

        return connectionString;
    }

    // Better: Use Managed Identity for database (no password needed)
    public async Task<string> GetManagedIdentityConnectionStringAsync()
    {
        string server = await GetSecretAsync("db-server");
        string database = await GetSecretAsync("db-name");

        // Use Managed Identity - no username/password in memory!
        string connectionString = $"Server={server};Database={database};" +
                                 "Authentication=Active Directory Managed Identity;" +
                                 "Encrypt=true;";

        return connectionString;
    }
}

// Startup configuration
public class Startup
{
    public void ConfigureServices(IServiceCollection services)
    {
        // Register Key Vault client as singleton
        string keyVaultUrl = Environment.GetEnvironmentVariable("AZURE_KEYVAULT_URL");
        services.AddSingleton<SecretManager>(sp => new SecretManager(keyVaultUrl));

        // Configure database with Managed Identity
        services.AddDbContext<ApplicationDbContext>((serviceProvider, options) =>
        {
            var secretManager = serviceProvider.GetRequiredService<SecretManager>();
            string connectionString = secretManager.GetManagedIdentityConnectionStringAsync().Result;
            options.UseSqlServer(connectionString);
        });
    }
}

// Example API controller using secrets securely
public class PaymentController : ControllerBase
{
    private readonly SecretManager _secretManager;

    public PaymentController(SecretManager secretManager)
    {
        _secretManager = secretManager;
    }

    [HttpPost("process")]
    public async Task<IActionResult> ProcessPayment([FromBody] PaymentRequest request)
    {
        // Retrieve API key only when needed (not stored in memory)
        string stripeApiKey = await _secretManager.GetSecretAsync("stripe-api-key");

        // Use API key immediately
        var stripeClient = new StripeClient(stripeApiKey);
        var result = await stripeClient.ProcessPaymentAsync(request);

        // Zero API key from memory immediately
        stripeApiKey = null;
        GC.Collect();

        return Ok(result);
    }
}

